      "keystrokes": "sed -n '1,260p' /app/plasmid.gb\n",
      "duration": 0.1
    },
    {
      "keystrokes": "python3 - <<'PY'\nfrom Bio import SeqIO\ntry:\n    recs=list(SeqIO.parse('/app/plasmid.gb','genbank'))\n    print('records', len(recs))\n    for rec in recs:\n        print('record', rec.id, rec.description, len(rec.seq))\n        print(str(rec.seq)[:200])\n        for i, feat in enumerate(rec.features):\n            print(i, feat.type, int(feat.location.start), int(feat.location.end), feat.qualifiers.get('label'), feat.qualifiers.get('product'), feat.qualifiers.get('translation'))\nexcept Exception as e:\n    print(type(e).__name__, e)\nPY\n",
      "duration": 1.0
    },
    {
      "keystrokes": "curl -s --connect-timeout 5 https://www.rcsb.org/ | head -5; echo '---'; curl -s --connect-timeout 5 'https://www.ebi.ac.uk/pdbe/api/pdb/entry/summary/2IB5' | python3 -m json.tool 2>/dev/null | head -30; echo '---'; curl -s --connect-timeout 5 'https://www.fpbase.org/api/4.0/proteins/?format=json' | head -c 500\n",
